def cache_result(ttl=300):
    cache = {}
    def decorator(func):
        def wrapper(*args):
            key = str(args)
            if key in cache and time.time() - cache[key][1] < ttl:
                return cache[key][0]
            result = func(*args)
            cache[key] = (result, time.time())
            return result
        return wrapper
    return decorator

